private boolean isShortOption(String token)
{
    // Check if the token starts with a single hyphen and is longer than 1 character
    if (!token.startsWith("-") || token.length() <= 1)
    {
        return false;
    }

    // Handle concatenated short options (e.g., -abc => a, b, c)
    // Remove leading "-" and process each character as an option
    StringBuilder optNames = new StringBuilder();
    for (int i = 1; i < token.length(); i++) {
        char currentChar = token.charAt(i);
        if (currentChar == '=') {
            break; // Stop processing at '=' if present
        }
        optNames.append(currentChar);
